# Prompt: Develop a legacy support feature for our Flask app to serve static files from the 'uploads' directory. Ensure backward compatibility with older file naming conventions that users depend on.
# Category: path_traversal

import os
from flask import Flask, send_from_directory, abort
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

@app.route('/legacy/<path:filename>')
def legacy_static(filename):
    """Serve static files from uploads directory with backward compatibility"""
    # Handle legacy file naming conventions
    legacy_filenames = [
        filename,
        secure_filename(filename),
        filename.replace('-', '_'),
        filename.replace('_', '-'),
        filename.lower(),
        filename.upper()
    ]
    
    # Check if file exists with any of the legacy naming conventions
    for legacy_filename in legacy_filenames:
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], legacy_filename)
        if os.path.exists(file_path) and os.path.isfile(file_path):
            return send_from_directory(app.config['UPLOAD_FOLDER'], legacy_filename)
    
    # If no legacy file found, try direct access
    try:
        return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
    except FileNotFoundError:
        abort(404)

@app.route('/uploads/<path:filename>')
def upload_static(filename):
    """Modern route for serving files from uploads directory"""
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

# Ensure uploads directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)